#include <bits/stdc++.h>
using namespace std;
const int N=2502;
struct Node{
    int num,id,data;
}x[N],y[N];
int n,p[N];
long long sum[N][N],ans=1;
bool cmp(Node a,Node b){
    return a.num<b.num;
}
long long f(int x1,int y1,int x2,int y2){
    if(y1>y2)
        return 0;
    return sum[x2][y2]-sum[x1-1][y2]-sum[x2][y1-1]+sum[x1-1][y1-1];
}
int main(){
    scanf("%d",&n);
    for(int i=1;i<=n;i++){
        scanf("%d%d",&x[i].num,&y[i].num);
        x[i].id=y[i].id=i;
    }
    sort(x+1,x+n+1,cmp);
    sort(y+1,y+n+1,cmp);
    for(int i=1;i<=n;i++)
    	x[x[i].id].data=i,y[y[i].id].data=i;
	for(int i=1;i<=n;i++)
		sum[x[i].data][y[i].data]=1,p[x[i].data]=y[i].data;
    for(int i=1;i<=n;i++)
        for(int j=1;j<=n;j++)
        	sum[i][j]=sum[i][j]+sum[i-1][j]+sum[i][j-1]-sum[i-1][j-1];
    for(int i=1;i<=n;i++)
        for(int j=i;j<=n;j++)
            ans+=(f(i,0,j,min(p[i],p[j])-1)+1)*(f(i,max(p[i],p[j])+1,j,n)+1);
    printf("%lld",ans);
    return 0; 
}
